Rules.InvariantScript:
// eliminate any items selected for deletion where 'delete items' button was not pressed
Clear(colDeleteLaborItems);
// hide the calculator
UpdateContext({locShowCalculator: false});
Reset(gal_Labor_Items)

// Remove each record from the local job labor collection
ForAll(
    colDeleteLaborItems,
    // If record was added by app then also remove from new records and deletions list
    With(
        {
            varType: "colCdsJobLaborItems",
            varRecordRef: colDeleteLaborItems[@'Job Labor Item']
        },
        If(
            varRecordRef in Filter(
                colAUDRecords,
                Type = "colCdsJobLaborItems"
                And Operation = "A"
            ).RecordRef,
            // if labor item was created on local device
            Remove(
                colCdsJobLaborItems,
                LookUp(
                    colCdsJobLaborItems,
                    'Job Labor Item' = varRecordRef
                )
            );
            Remove(
                colAUDRecords,
                LookUp(
                    colAUDRecords,
                    Type = "colCdsJobLaborItems"
                    And RecordRef = varRecordRef
                    And Operation = "A"
                )
            ),
            // if labor item was downloaded from the server
            Collect(
                colAUDRecords,
                {
                    Type: varType,
                    RecordRef: varRecordRef,
                    Job: gblRecordJobCurrent.Job,
                    Operation: "D"
                }
            )
        )
    )
);
UpdateIf(
    colCdsJobLaborItems,
    'Job Labor Item' in Filter(
        colAUDRecords,
        Type = "colCdsJobLaborItems",
        Operation = "D").RecordRef,
    {
        Status: gblOptionSets.JobLaborItem.Status.Inactive,
        'Status Reason': gblOptionSets.JobLaborItem.StatusReason.Inactive
    }
);
// save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobLaborItems,
        "localCdsJobLaborItems"
    );
);

If(
    IsBlank(
        LookUp(
            colAUDRecords,
            Type = "colCdsJobLaborItems" And RecordRef = ThisItem.'Job Labor Item' And Operation = "D"
        )
    ),
    DisplayMode.Edit,
    DisplayMode.View
)

Navigate(
    'Add Note Screen',
    ScreenTransition.None,
    {
        locRecordNoteCurrent: {
            TableName: "Job Labor Items",
            GUID: ThisItem.'Job Labor Item',
            BackScreen: App.ActiveScreen,
            Notes: ThisItem.Notes
        }
    }
);

If(
    ThisItem.'Job Labor Item' in colDeleteLaborItems.'Job Labor Item',
    Remove(
        colDeleteLaborItems,
        LookUp(
            colDeleteLaborItems,
            'Job Labor Item' = ThisItem.'Job Labor Item'
        )
    ),
    Collect(
        colDeleteLaborItems,
        ThisItem
    )
);

With(
    {
        varType: "colCdsJobLaborItems",
        varRecordRef: gal_Labor_Items.Selected.'Job Labor Item'
    },
    Patch(
        colCdsJobLaborItems,
        LookUp(
            colCdsJobLaborItems,
            'Job Labor Item' = varRecordRef
        ),
        {Quantity: cmp_Labor_Calculator.Value}
    );
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
// save local changes
IfError( // This line of code is added to hide the errors
If(
    gblAppLoadOffline,
    SaveData(
        colCdsJobLaborItems,
        "localCdsJobLaborItems"
    );
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
)
,Blank())  // This line of code is added to hide the errors
;
// Hide and reset calculator
UpdateContext(
    {
        locShowCalculator: false,
        locResetCalculator: true
    }
);
UpdateContext({locResetCalculator: false})
